import string
import random
from database import get_db

class URLModel:
    @staticmethod
    def generate_short_code(length=6):
        chars = string.ascii_letters + string.digits
        return ''.join(random.choice(chars) for _ in range(length))

    @staticmethod
    def create_url(original_url):
        short_code = URLModel.generate_short_code()
        with get_db() as conn:
            cursor = conn.cursor()
            try:
                cursor.execute(
                    'INSERT INTO urls (original_url, short_code) VALUES (?, ?)',
                    (original_url, short_code)
                )
                conn.commit()
                return short_code
            except Exception:
                # In case of collision, try once more (simplistic)
                short_code = URLModel.generate_short_code()
                cursor.execute(
                    'INSERT INTO urls (original_url, short_code) VALUES (?, ?)',
                    (original_url, short_code)
                )
                conn.commit()
                return short_code

    @staticmethod
    def get_url(short_code):
        with get_db() as conn:
            row = conn.execute(
                'SELECT original_url FROM urls WHERE short_code = ?',
                (short_code,)
            ).fetchone()
            return row['original_url'] if row else None
